using Smoower.Minified.EFCore;namespace Smoower.Minified.Tests;public class QueryExtensionsTests{private static async Task<TestDb> Seed(string name){var db = TestDbFactory.Create(name);db.Things.AddRange(new Thing { Name = "b", Rank = 2 },new Thing { Name = "a", Rank = 1 },new Thing { Name = "c", Rank = 3 });await db.SaveChangesAsync();return db;}[F]public async Task W_FiltersRows(){var db = await Seed(nameof(W_FiltersRows));(await db.Things.w(t => t.Rank >= 2).lst()).Count.eq(2);}[F]public async Task S_Projects(){var db = await Seed(nameof(S_Projects));(await db.Things.ob(t => t.Rank).s(t => t.Name).lst()).eqSeq(new[] { "a", "b", "c" });}[F]public async Task ObdAndPaging_Work(){var db = await Seed(nameof(ObdAndPaging_Work));(await db.Things.obd(t => t.Rank).sk(1).tk(1).s(t => t.Name).lst()).eqSeq(new[] { "b" });}[F]public async Task ObThenBy_Work(){var db = await Seed(nameof(ObThenBy_Work));(await db.Things.ob(t => t.Rank).tb(t => t.Name).s(t => t.Name).lst()).eqSeq(new[] { "a", "b", "c" });}[F]public async Task One_ReturnsMatchOrNull(){var db = await Seed(nameof(One_ReturnsMatchOrNull));(await db.Things.w(t => t.Name == "a").one()).notNul();(await db.Things.w(t => t.Name == "zzz").one()).nul();}[F]public async Task Single_ReturnsMatch(){var db = await Seed(nameof(Single_ReturnsMatch));(await db.Things.w(t => t.Rank == 3).single())!.Name.eq("c");}[F]public async Task AnyAndCount_Work(){var db = await Seed(nameof(AnyAndCount_Work));(await db.Things.any()).tru();(await db.Things.w(t => t.Rank > 99).any()).fls();(await db.Things.cnt()).eq(3);}[F]public async Task Nt_DoesNotTrack(){var name = nameof(Nt_DoesNotTrack);(await Seed(name)).Dispose();var db = TestDbFactory.Create(name);(await db.Things.nt().w(t => t.Name == "a").one()).notNul();db.ChangeTracker.Entries().empty();}}
